from manim import *

class CustomAnimation(Animation):
    def interpolate(self, alpha):
        super().interpolate(alpha)
        print(f"Interpolating at {alpha}")

@override_animation(CustomAnimation)
    def custom_interpolate_function(self, alpha):
        print(f"Custom interpolation at {alpha}")
        return CustomAnimation.interpolate(self, alpha)

class OverrideAnimationExample(Scene):
    def construct(self):
        # 创建动画对象
        mobject = Square()
        anim = CustomAnimation(mobject)

        # 添加并播放自定义覆盖的动画
        self.add(mobject)
        self.play(anim)

